INSERT INTO tasks (class_level, topic, question, options_json, correct_index, explanation, points) VALUES
(10,'Ток','Какъв е енергийният преход в генератор на променлив ток?','["Механична енергия се превръща в електрична енергия","Електрична енергия се превръща в механична","Топлинна енергия се превръща в електрична","Химична енергия се превръща в електрична"]',0,'В генератора на променлив ток механичната енергия от въртенето се преобразува в електрична енергия.',1),
(10,'Ток','Променливият ток в САЩ е с честота 60 Hz. Какъв е периодът на този ток?','["0.6 s","0.167 s","0.0167 s","60 s"]',2,'Периодът на променлив ток се намира от T = 1/f = 1/60 s ≈ 0.0167 s.',2),
(10,'Ток','Амперметър, включен във верига с променлив ток, показва 5 A. Каква стойност на тока измерва уредът?','["Максималната стойност","Средната стойност","Ефективната стойност","Моментната стойност"]',2,'Амперметрите за променлив ток измерват ефективната стойност на тока.',1),
(10,'Ток','Електрическа крушка е свързана към мрежа с ефективно напрежение 220 V. Ако ефективният ток през нея е 0.5 A, какво е съпротивлението на крушката?','["110 Ω","220 Ω","440 Ω","880 Ω"]',2,'За ефективни стойности важи законът на Ом: R = U/I = 220 V / 0.5 A = 440 Ω.',2);
